              cx: 18,
              cy: 18,
              r: 15.5,
              pathLength: 100,
              style: {
                strokeDasharray: `${overPct} ${100 - overPct}`,
                '--over-dasharray': `${overPct} ${100 - overPct}`,
                '--over-offset': -(100 - overPct),
                stroke: overColor
              }
