                kind: current.payload?.type === 'slot' ? 'slot' : 'task',
                title: current.title || '',
                badgeText: current.badgeText || '',
                parentGroupLabel: current.parentGroupLabel || '',
                accentColor: current.accentColor || '',
                background: current.background || '',
                x: current.lastX,
                y: current.lastY,
                height: sourceHeight,
                width: sourceWidth,
                grabOffsetX,
                grabOffsetY,
